class Solution {
public:
    long long minimumSteps(string s) {
        int n = s.size();
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '1') {
                count++;
            }
        }
        int res = count;
        for (int i = 0; i < n; i++) {
            if (s[i] == '1') {
                count--;
            } else {
                count++;
            }
            res = min(res, count);
        }
        return res;
    }
};
